// ----- GAME VARIABLES -----
var gameState = "start";
var score = 0;
var health = 100;
var damage = 10;

// ----- ROAD LANE VALUES -----
var roadTop1 = 10;
var roadBottom1 = 90;

var roadTop2 = 110;
var roadBottom2 = 190;

var roadTop3 = 210;
var roadBottom3 = 290;

var roadTop4 = 310;
var roadBottom4 = 380;

// ----- FUNCTIONS -----
function randomRoadY() {
  var section = randomNumber(1,4);

  if (section === 1) {
    return randomNumber(roadTop1, roadBottom1);
  }
  if (section === 2) {
    return randomNumber(roadTop2, roadBottom2);
  }
  if (section === 3) {
    return randomNumber(roadTop3, roadBottom3);
  }
  if (section === 4) {
    return randomNumber(roadTop4, roadBottom4);
  }
}

function resetCar(car) {
  if (car.x > 400) {
    car.x = randomNumber(-300,0);
    car.y = randomRoadY();
  }
}

function resetItem(item) {
  if (item.x > 420) {
    item.x = randomNumber(-400,-100);
    item.y = randomRoadY();
  }
}

// ----- CREATE CARS -----
var carAnimations = ["car_black","car_blue","car_green","car_red","car_yellow"];
var cars = [];

for (var i = 0; i < carAnimations.length; i++) {
  var car = createSprite(0, randomRoadY());
  car.setAnimation(carAnimations[i]);
  car.scale = 0.8;
  car.velocityX = randomNumber(2,5);
  cars.push(car);
}

// ----- OTHER SPRITES -----
var kid = createSprite(350, 200);
kid.setAnimation("angry kid");
kid.scale = 0.2;

var medkit = createSprite(-100, 200);
medkit.setAnimation("first_aid");
medkit.scale = 0.4;
medkit.velocityX = 3;

var coin = createSprite(-300, 200);
coin.setAnimation("coin_gold");
coin.scale = 0.6;
coin.velocityX = 4;


// ----- DRAW LOOP -----
function draw() {

// ----- PAUSE BUTTON -----
if (keyWentDown("p")) {
  if (gameState === "play") {
    gameState = "pause";
  } else if (gameState === "pause") {
    gameState = "play";
  }
}
if (gameState === "start") {
    background("black");
    fill("yellow");
    textSize(45);
    textAlign(CENTER);
    text("SPEED RACER 2.0", 200, 100);

    textSize(20);
    fill("blue");
    text("Press SPACE to Start", 200, 140);
    text("press p to pause", 200, 160);
    text("controls", 200, 230);
    // 
    fill("red");
    text("↑ Move Up", 200, 260);
    text("↓ Move Down", 200, 290);
    text("D die", 200, 320);
    text("P paused", 200, 350);
    // 
    fill("yellow");
    text("=====================================================================", 0, 50);
    text("=====================================================================", 0, 180);

    if (keyDown("space")) {
      gameState = "play";
    }
    return;
  }

if (gameState === "pause") {
  background("black");
  fill("red");
  textSize(40);
  textAlign(CENTER);
  text("PAUSED", 200, 180);
  textSize(20);
  fill("blue");
  text("Press P to Resume", 200, 220);
  fill("yellow");
  text("=====================================================================", 0, 130);
  text("=====================================================================", 0, 240);
  return;
}
if (gameState === "end") {
    background("black");
    fill("red");
    textSize(50);
    textAlign(CENTER);
    text("GAME OVER", 200, 160);
    text("YOU HAVE DIED", 200, 100);

    fill("blue");
    textSize(25);
    text("Score: " + score, 200, 220);
    fill("yellow");
    text("=====================================================================", 0, 50);
    text("=====================================================================", 0, 190);
    text("=====================================================================", 0, 240);
    return;
  }

if (health <= 0) {
    gameState = "end";
  }

if (keyDown("d")) {
  gameState = "end";
}

if ((gameState === "play")) {
  background(rgb(66,66,66));
}
// crosswalk
fill("white");
rect(300, 0, 100, 50);
rect(300, 70, 100, 50);
rect(300, 140, 100, 50);
rect(300, 210, 100, 50);
rect(300, 280, 100, 50);
rect(300, 350, 100, 50);

  // Road borders
fill("gray");
rect(0,0,400,10);
rect(0,390,400,10);

  // Yellow lane lines
fill("yellow");
rect(0,90,250,10);
rect(0,110,250,10);
rect(0,190,250,10);
rect(0,210,250,10);
rect(0,290,250,10);
rect(0,310,250,10);

  // Cars
for (var i = 0; i < cars.length; i++) {
    resetCar(cars[i]);

    if (kid.isTouching(cars[i])) {
      health -= damage;
      cars[i].x = -400;
    }
  }

  // Items
resetItem(medkit);
resetItem(coin);

if (kid.isTouching(coin)) {
    score += 1;
    coin.x = -400;
  }

if (kid.isTouching(medkit)) {
    health += 20;
    if (health > 100) health = 100;
    medkit.x = -400;
  }

  // Movement
if (keyDown("up")) {
    kid.y -= 5;
  }
if (keyDown("down")) {
    kid.y += 5;
  }

if (health < 0) health = 0;

drawSprites();

fill("black");
textSize(20);
text("Health: " + health, 280, 30);
text("Score: " + score, 280, 60);
}
